    function adminWithdrawBNB() external onlyOwner {
        payable(owner()).transfer(address(this).balance);
    }

    // ============================================================================
    //                           视图函数
    // ============================================================================

    /**
     * @notice 获取用户信息
     */
    function getUser(address _user) external view returns (
        address referrer,
        uint256 directCount,
        uint8 level,
        uint8 dLevel,
        uint256 totalInvest,
        uint256 teamInvest,
        uint256 energy,
        uint256 directSales,
        bool hasNode,
        bool hasDeposited,
        uint256 activeLineCount
    ) {
        User storage u = _users[_user];
        return (
            u.referrer,
            u.directCount,
            u.level,
            u.dLevel,
            u.totalInvest,
            u.teamInvest,
            u.energy,
            u.directSales,
            u.hasNode,
            u.hasDeposited,
            u.activeLineCount
        );
